insert into public.dishes(id,slug,name,category,tags,difficulty,cook_minutes,servings,description,emoji,tone,tips,video_url,featured,active) values('31','dish-31','肉末茄子','荤菜',array['软糯','下饭']::text[],'简单',30,2,'把茄子、肉末做得恰到好处，是很适合两个人晚餐的一道肉末茄子。','🍆','purple',array['食材下锅前尽量沥干水分，味道更香，也更安全。','最后尝味再补盐，避免调味过重。']::text[],'https://search.bilibili.com/all?keyword=%E8%82%89%E6%9C%AB%E8%8C%84%E5%AD%90%20%E5%AE%B6%E5%B8%B8%E5%81%9A%E6%B3%95',false,true) on conflict(id) do update set slug=excluded.slug,name=excluded.name,category=excluded.category,tags=excluded.tags,difficulty=excluded.difficulty,cook_minutes=excluded.cook_minutes,servings=excluded.servings,description=excluded.description,emoji=excluded.emoji,tone=excluded.tone,tips=excluded.tips,video_url=excluded.video_url,featured=excluded.featured,active=true;
